import React, { useState, useEffect, useMemo, useDeferredValue } from 'react';
import axios from 'axios';
import { FileBarChart, Download, Settings, ChevronDown, ChevronUp } from 'lucide-react';
import './Reports.css';

const FORMATS = [
  "Accounting Summary",
  "Full Detailed Log",
  "Period Closing (Activity Summary)",
  "Student Academic Status Report",
];

export default function Reports() {
  const [loading, setLoading] = useState(false);
  const [reportData, setReportData] = useState<{ columns: string[], data: any[] }>({ columns: [], data: [] });
  const [hasGenerated, setHasGenerated] = useState(false);
  const [configOpen, setConfigOpen] = useState(true);

  // Table state
  const [sortConfig, setSortConfig] = useState<{ key: string; direction: 'asc' | 'desc' } | null>(null);
  const [columnFilters, setColumnFilters] = useState<{ [key: string]: string }>({});
  const [currentPage, setCurrentPage] = useState(1);
  const rowsPerPage = 100;

  // Dynamic Lookups
  const [availableColleges, setAvailableColleges] = useState<string[]>([]);
  const [availableTerms, setAvailableTerms] = useState<string[]>([]);
  const [availableYears, setAvailableYears] = useState<number[]>([]);
  const [availableStatuses, setAvailableStatuses] = useState<string[]>([]);

  // Filters
  const [format, setFormat] = useState(FORMATS[0]);
  const [colleges, setColleges] = useState<string[]>([]);
  const [terms, setTerms] = useState<string[]>([]);
  const [years, setYears] = useState<number[]>([]);
  const [statuses, setStatuses] = useState<string[]>([]);
  const [startDate, setStartDate] = useState('');
  const [endDate, setEndDate] = useState('');

  useEffect(() => {
    const fetchLookups = async () => {
      try {
        const token = localStorage.getItem('token');
        const response = await axios.get(`${import.meta.env.VITE_API_BASE_URL || 'http://127.0.0.1:8000'}/api/lookups`, {
          headers: { Authorization: `Bearer ${token}` }
        });
        setAvailableColleges(response.data.colleges || []);
        setAvailableTerms(response.data.terms || []);
        setAvailableYears(response.data.years || []);
        setAvailableStatuses(response.data.statuses || []);
      } catch (error) {
        console.error("Failed to fetch lookups", error);
      }
    };
    fetchLookups();
  }, []);

  const handleMultiSelect = (setter: React.Dispatch<React.SetStateAction<any[]>>, value: any) => {
    setter(prev => prev.includes(value) ? prev.filter(item => item !== value) : [...prev, value]);
  };

  const buildParams = () => {
    const params: any = { format: format };
    if (colleges.length) params.colleges = colleges;
    if (terms.length) params.terms = terms;
    if (years.length) params.years = years;
    if (statuses.length) params.statuses = statuses;
    if (startDate) params.start_date = startDate;
    if (endDate) params.end_date = endDate;
    return params;
  };

  const serializeParams = (params: any) => {
    const searchParams = new URLSearchParams();
    for (const key in params) {
      if (Array.isArray(params[key])) {
        params[key].forEach((val: any) => searchParams.append(key, val));
      } else if (params[key] !== undefined && params[key] !== null && params[key] !== '') {
        searchParams.append(key, params[key]);
      }
    }
    return searchParams.toString();
  };

  const handleGenerate = async (e: React.FormEvent) => {
    e.preventDefault();
    if (format === "Period Closing (Activity Summary)" && (!startDate || !endDate)) {
      alert("Please select both start and end dates for Period Closing report.");
      return;
    }
    
    setLoading(true);
    setHasGenerated(true);
    
    try {
      const token = localStorage.getItem('token');
      const response = await axios.get(`${import.meta.env.VITE_API_BASE_URL || 'http://127.0.0.1:8000'}/api/reports/generate`, {
        params: buildParams(),
        paramsSerializer: serializeParams,
        headers: { Authorization: `Bearer ${token}` }
      });
      setReportData(response.data);
      // Auto-collapse config panel if data is found to maximize table space
      if (response.data.data.length > 0) {
        setConfigOpen(false);
      }
    } catch (error) {
      console.error("Error generating report", error);
      setReportData({ columns: [], data: [] });
    } finally {
      setLoading(false);
    }
  };

  const downloadExcel = async () => {
    try {
      const token = localStorage.getItem('token');
      const response = await axios.get(`${import.meta.env.VITE_API_BASE_URL || 'http://127.0.0.1:8000'}/api/reports/excel`, {
        params: buildParams(),
        paramsSerializer: serializeParams,
        headers: { Authorization: `Bearer ${token}` },
        responseType: 'blob'
      });
      
      const url = window.URL.createObjectURL(new Blob([response.data]));
      const link = document.createElement('a');
      link.href = url;
      link.setAttribute('download', `Report_${format.replace(/ /g, '_')}.xlsx`);
      document.body.appendChild(link);
      link.click();
      link.parentNode?.removeChild(link);
    } catch (error) {
      console.error("Error downloading report", error);
    }
  };

  const formatValue = (col: string, val: any) => {
    if (typeof val === 'number') {
      if (col.toLowerCase().includes('id') || col.toLowerCase().includes('year')) {
        return val.toString();
      }
      return new Intl.NumberFormat('en-EG', { maximumFractionDigits: 2 }).format(val);
    }
    return val;
  };

  const handleSort = (col: string) => {
    let direction: 'asc' | 'desc' = 'asc';
    if (sortConfig && sortConfig.key === col && sortConfig.direction === 'asc') {
      direction = 'desc';
    }
    setSortConfig({ key: col, direction });
  };

  const handleFilterChange = (col: string, value: string) => {
    setColumnFilters(prev => ({ ...prev, [col]: value }));
  };

  const deferredFilters = useDeferredValue(columnFilters);
  const deferredSortConfig = useDeferredValue(sortConfig);

  const processedData = useMemo(() => {
    if (!reportData || !reportData.data.length) return [];
    
    // Separate TOTAL row
    const dataRows = reportData.data.filter(row => row["Student Name"] !== "TOTAL");
    const totalRow = reportData.data.find(row => row["Student Name"] === "TOTAL");

    // Filter
    let filtered = dataRows.filter(row => {
      for (const col in deferredFilters) {
        if (!deferredFilters[col]) continue;
        const cellValue = String(row[col]).toLowerCase();
        if (!cellValue.includes(deferredFilters[col].toLowerCase())) {
          return false;
        }
      }
      return true;
    });

    // Sort
    if (deferredSortConfig) {
      filtered.sort((a, b) => {
        let aVal = a[deferredSortConfig.key];
        let bVal = b[deferredSortConfig.key];
        // Handle nulls
        if (aVal == null) aVal = "";
        if (bVal == null) bVal = "";
        
        if (aVal < bVal) return deferredSortConfig.direction === 'asc' ? -1 : 1;
        if (aVal > bVal) return deferredSortConfig.direction === 'asc' ? 1 : -1;
        return 0;
      });
    }

    if (totalRow) {
      const dynamicSubtotal: any = { ...totalRow };
      dynamicSubtotal["Student Name"] = "SUBTOTAL";
      
      // Reset numeric fields to 0
      for (const col of reportData.columns) {
        if (typeof totalRow[col] === 'number') {
          dynamicSubtotal[col] = 0;
        }
      }

      // Sum up the filtered rows
      for (const row of filtered) {
        for (const col of reportData.columns) {
          if (typeof totalRow[col] === 'number') {
            dynamicSubtotal[col] += (Number(row[col]) || 0);
          }
        }
      }
      filtered.push(dynamicSubtotal);
    }
    
    return filtered;
  }, [reportData, deferredFilters, deferredSortConfig]);

  // Reset to page 1 when filters or sort change
  useEffect(() => {
    setCurrentPage(1);
  }, [deferredFilters, deferredSortConfig]);

  // Pagination logic
  const totalRows = processedData.length > 0 && (processedData[processedData.length - 1]["Student Name"] === "SUBTOTAL" || processedData[processedData.length - 1]["Student Name"] === "TOTAL") 
    ? processedData.length - 1 
    : processedData.length;
    
  const totalPages = Math.ceil(totalRows / rowsPerPage) || 1;
  const startIndex = (currentPage - 1) * rowsPerPage;
  
  const paginatedData = useMemo(() => {
    const dataRows = processedData.slice(0, totalRows);
    const subtotalRow = processedData.length > totalRows ? processedData[processedData.length - 1] : null;
    
    const currentSlice = dataRows.slice(startIndex, startIndex + rowsPerPage);
    if (subtotalRow) {
      currentSlice.push(subtotalRow);
    }
    return currentSlice;
  }, [processedData, startIndex, totalRows]);

  return (
    <div className="page-container reports-container">
      <header className="page-header">
        <h1 className="page-title">Financial Management Reports</h1>
        <p className="page-subtitle">Generate dynamic reports with advanced filtering capabilities.</p>
      </header>

      <div className="reports-layout-top">
        <section className="reports-config-panel glass-panel animate-fade-in">
          <div className="config-header" onClick={() => setConfigOpen(!configOpen)} style={{ cursor: 'pointer' }}>
            <div className="sidebar-title" style={{ marginBottom: 0, borderBottom: 'none', paddingBottom: 0 }}>
              <Settings size={18} /> Configuration
            </div>
            <button className="btn-toggle-config">
              {configOpen ? <ChevronUp size={20} /> : <ChevronDown size={20} />}
            </button>
          </div>
          
          {configOpen && (
            <form onSubmit={handleGenerate} className="reports-form-grid">
              <div className="form-row-top">
                <div className="form-group">
                  <label>Report Format</label>
                  <select value={format} onChange={e => setFormat(e.target.value)} required>
                    {FORMATS.map(f => <option key={f} value={f}>{f}</option>)}
                  </select>
                </div>

                <div className="form-group">
                  <label>Date Range (Optional)</label>
                  <div className="date-inputs-row">
                    <input type="date" value={startDate} onChange={e => setStartDate(e.target.value)} />
                    <span className="date-separator">to</span>
                    <input type="date" value={endDate} onChange={e => setEndDate(e.target.value)} />
                  </div>
                </div>

                <div className="form-group">
                  <label>Year</label>
                  <select 
                    value={years.length > 0 ? years[0].toString() : ""} 
                    onChange={e => {
                      const val = e.target.value;
                      setYears(val ? [parseInt(val)] : []);
                    }}
                  >
                    <option value="">All Years</option>
                    {availableYears.map(y => (
                      <option key={y} value={y}>{y}</option>
                    ))}
                  </select>
                </div>
              </div>

              <div className="form-row-bottom">
                <div className="filter-group">
                  <label>Colleges</label>
                  <div className="checkbox-row">
                    {availableColleges.map(c => (
                      <label key={c} className="custom-checkbox">
                        <input type="checkbox" checked={colleges.includes(c)} onChange={() => handleMultiSelect(setColleges, c)} />
                        <span>{c}</span>
                      </label>
                    ))}
                  </div>
                </div>

                <div className="filter-group">
                  <label>Terms</label>
                  <div className="checkbox-row">
                    {availableTerms.map(t => (
                      <label key={t} className="custom-checkbox">
                        <input type="checkbox" checked={terms.includes(t)} onChange={() => handleMultiSelect(setTerms, t)} />
                        <span>{t}</span>
                      </label>
                    ))}
                  </div>
                </div>
                
                <div className="action-group">
                  <button type="submit" className="btn-generate" disabled={loading}>
                    {loading ? <div className="spinner-small"></div> : <FileBarChart size={18} />}
                    Generate Report
                  </button>
                </div>
              </div>
            </form>
          )}
        </section>

        <section className="reports-content glass-panel animate-fade-in">
          {!hasGenerated ? (
            <div className="empty-state">
              <FileBarChart size={48} style={{ opacity: 0.5, marginBottom: '16px' }} />
              <h3>No Report Generated</h3>
              <p>Select your filters and click generate to view data.</p>
            </div>
          ) : loading ? (
            <div className="empty-state">
              <div className="spinner-large"></div>
              <p>Aggregating financial data...</p>
            </div>
          ) : reportData.data.length === 0 ? (
            <div className="empty-state">
              <h3>No Data Found</h3>
              <p>Your filter criteria did not match any records.</p>
            </div>
          ) : (
            <div className="results-container">
              <div className="results-header">
                <h3>{format}</h3>
                <button onClick={downloadExcel} className="btn-download-excel">
                  <Download size={16} /> Export to Excel
                </button>
              </div>
              <div className="table-responsive">
                <table className="data-table reports-table">
                  <thead style={{ position: 'sticky', top: 0, zIndex: 1 }}>
                    <tr>
                      {reportData.columns.map((col, i) => (
                        <th key={i} style={{ minWidth: '150px' }}>
                          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', cursor: 'pointer' }} onClick={() => handleSort(col)}>
                            <span>{col}</span>
                            <span style={{ fontSize: '0.8rem', opacity: sortConfig?.key === col ? 1 : 0.3 }}>
                              {sortConfig?.key === col ? (sortConfig.direction === 'asc' ? '▲' : '▼') : '↕'}
                            </span>
                          </div>
                          <input 
                            type="text" 
                            placeholder={`Filter ${col}...`} 
                            value={columnFilters[col] || ''}
                            onChange={(e) => handleFilterChange(col, e.target.value)}
                            onClick={(e) => e.stopPropagation()}
                            style={{ width: '100%', marginTop: '8px', padding: '6px 8px', fontSize: '0.75rem', fontWeight: 'normal', border: '1px solid var(--border-color)', borderRadius: '4px', background: 'var(--bg-color)', color: 'var(--text-primary)', outline: 'none' }}
                          />
                        </th>
                      ))}
                    </tr>
                  </thead>
                  <tbody>
                    {paginatedData.map((row, i) => (
                      <tr key={i} className={(row["Student Name"] === "TOTAL" || row["Student Name"] === "SUBTOTAL") ? "total-row" : ""}>
                        {reportData.columns.map((col, j) => (
                          <td key={j} className={typeof row[col] === 'number' ? 'text-right' : ''}>
                            {formatValue(col, row[col])}
                          </td>
                        ))}
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
              
              {totalPages > 1 && (
                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', padding: '16px', borderTop: '1px solid var(--border-color)', background: 'var(--surface-color)', borderRadius: '0 0 var(--glass-radius) var(--glass-radius)' }}>
                  <span style={{ fontSize: '0.85rem', color: 'var(--text-secondary)' }}>
                    Showing {startIndex + 1} to {Math.min(startIndex + rowsPerPage, totalRows)} of {totalRows} entries
                  </span>
                  <div style={{ display: 'flex', gap: '8px' }}>
                    <button 
                      className="btn-secondary" 
                      onClick={() => setCurrentPage(p => Math.max(1, p - 1))}
                      disabled={currentPage === 1}
                      style={{ padding: '4px 12px', fontSize: '0.85rem' }}
                    >
                      Previous
                    </button>
                    <span style={{ display: 'flex', alignItems: 'center', padding: '0 8px', fontSize: '0.85rem', fontWeight: 600 }}>
                      Page {currentPage} of {totalPages}
                    </span>
                    <button 
                      className="btn-secondary" 
                      onClick={() => setCurrentPage(p => Math.min(totalPages, p + 1))}
                      disabled={currentPage === totalPages}
                      style={{ padding: '4px 12px', fontSize: '0.85rem' }}
                    >
                      Next
                    </button>
                  </div>
                </div>
              )}
            </div>
          )}
        </section>
      </div>
    </div>
  );
}

